/bin/bash -lc "python3 - <<'PY'
import re,json,urllib.request
vuln_pkgs=[]
for line in open('/tmp/dependency-list.txt'):
    m=re.match(r'\\s+(["'^:]+):([''^:]+):[''^:]+:(?:[''^:]+:)?([''^:]+):(compile|runtime|test|provided)'"', line)
    if m: vuln_pkgs.append(m.groups())
queries=[{\"version\":v,\"package\":{\"ecosystem\":\"Maven\",\"name\":f\"{g}:{a}\"}} for g,a,v,s in vuln_pkgs]
allres=[]
for i in range(0,len(queries),100):
    req=urllib.request.Request('https://api.osv.dev/v1/querybatch', data=json.dumps({\"queries\":queries[i:i+100]}).encode(), headers={'Content-Type':'application/json'})
    with urllib.request.urlopen(req, timeout=60) as r: allres.extend(json.load(r)['results'])
ids=[]
for c,res in zip(vuln_pkgs,allres):
    if res.get('vulns'):
        ids += [v['id'] for v in res['vulns']]
ids=sorted(set(ids))
print('vulns',len(ids))
for vid in ids:
    req=urllib.request.Request('https://api.osv.dev/v1/vulns/'+vid)
    with urllib.request.urlopen(req, timeout=60) as r: v=json.load(r)
    aliases=','.join(v.get('aliases') or [])
    print('\\n###',vid,aliases)
    print(v.get('summary',''))
    for aff in v.get('affected',[]):
        pkg=aff.get('package',{})
        if pkg.get('ecosystem')=='Maven':
            print('PKG',pkg.get('name'))
            fixed=[]
            for rng in aff.get('ranges',[]):
                for ev in rng.get('events',[]):
                    if 'fixed' in ev: fixed.append(ev['fixed'])
            print('FIXED', ','.join(fixed) or 'none')
PY"

